import json
import pandas as pd
import re

reviews = var_call_Tzw5wuXrfz0fZPp6KIY0IoYC
businesses_fp = var_call_96SNTbzlbKEuQv05n59y1lZY

# Load businesses JSON
with open(businesses_fp, 'r') as f:
    businesses = json.load(f)

bdf = pd.DataFrame(businesses)
# normalize column names
bdf.columns = [c if isinstance(c, str) else str(c) for c in bdf.columns]

# Ensure description exists
bdf['description'] = bdf.get('description', None)

# Extract state
state_codes = {"AL","AK","AZ","AR","CA","CO","CT","DE","FL","GA","HI","ID","IL","IN","IA","KS","KY","LA","ME","MD","MA","MI","MN","MS","MO","MT","NE","NV","NH","NJ","NM","NY","NC","ND","OH","OK","OR","PA","RI","SC","SD","TN","TX","UT","VT","VA","WA","WV","WI","WY"}

def extract_state(desc):
    if not isinstance(desc, str):
        return None
    # try patterns like ', XX,' or ' in City, ST,' or 'City, ST '
    m = re.search(r",\s*([A-Z]{2})\b", desc)
    if m and m.group(1) in state_codes:
        return m.group(1)
    # fallback: tokens
    toks = re.findall(r"\b([A-Z]{2})\b", desc)
    for t in toks:
        if t in state_codes:
            return t
    return None

bdf['state'] = bdf['description'].apply(extract_state)

# create business_ref to join
if 'business_id' in bdf.columns:
    bdf['business_ref'] = bdf['business_id'].astype(str).str.replace('businessid_', 'businessref_')
else:
    bdf['business_ref'] = None

# Prepare reviews aggregated dataframe
radf = pd.DataFrame(reviews)
# Ensure columns exist
if 'business_ref' not in radf.columns:
    radf['business_ref'] = None
if 'review_count' in radf.columns:
    radf['review_count'] = pd.to_numeric(radf['review_count'], errors='coerce').fillna(0).astype(int)
else:
    radf['review_count'] = 0
if 'avg_rating' in radf.columns:
    radf['avg_rating'] = pd.to_numeric(radf['avg_rating'], errors='coerce')
else:
    radf['avg_rating'] = None

# Merge
merged = pd.merge(radf, bdf[['business_ref','state']], on='business_ref', how='left')

# Filter to rows with state
merged = merged[merged['state'].notnull()].copy()

if merged.empty:
    result = {"state": None, "total_reviews": None, "avg_business_rating": None}
else:
    grp = merged.groupby('state').agg(total_reviews=('review_count','sum'), avg_business_rating=('avg_rating','mean')).reset_index()
    top = grp.loc[grp['total_reviews'].idxmax()]
    result = {"state": top['state'], "total_reviews": int(top['total_reviews']), "avg_business_rating": float(round(top['avg_business_rating'],4))}

print("__RESULT__:")
print(json.dumps(result))

